query:
UPDATE sms_templates SET body = 'Hi {{first_name}}! This is Scott Boerstra with Alta Mortgage Group. Thanks for your interest — I''d love to help you with your home financing goals. Expect a call from us shortly. Questions? Reply here anytime. Reply STOP to opt out.' WHERE id = 1;

UPDATE sms_templates SET body = 'Hi {{first_name}}, you''re officially registered for "{{webinar_title}}" on {{session_date}}! 🎉 Save this link to join: {{webinar_link}} — We''ll send a reminder before it starts. Reply STOP to opt out.' WHERE id = 2;

UPDATE sms_templates SET body = 'Hi {{first_name}}, just a reminder — "{{webinar_title}}" is TOMORROW at {{session_date}}! Your join link: {{webinar_link}} — Add it to your calendar so you don''t miss it. See you there! Reply STOP to opt out.' WHERE id = 3;

UPDATE sms_templates SET body = 'Hi {{first_name}}, "{{webinar_title}}" starts in 1 HOUR! Click here to join now: {{webinar_link}} — We''re excited to see you. Reply STOP to opt out.' WHERE id = 4;

UPDATE sms_templates SET body = 'Hi {{first_name}}, thank you for attending "{{webinar_title}}" today! It was great having you. Ready to take the next step toward homeownership? Reply YES and we''ll schedule a free consultation. Reply STOP to opt out.' WHERE id = 5;

UPDATE sms_templates SET body = 'Hi {{first_name}}, we missed you at "{{webinar_title}}" today! No worries — reply REPLAY and we''ll send you the recording link. We''d still love to help you on your homeownership journey. Reply STOP to opt out.' WHERE id = 6;

UPDATE sms_templates SET body = 'Hi {{first_name}}, your consultation with Scott Boerstra at Alta Mortgage Group is confirmed! We''ll review your goals and walk you through your best loan options. Check your email for details. Questions? Just reply here. Reply STOP to opt out.' WHERE id = 7;

UPDATE sms_templates SET body = 'Hi {{first_name}}, congratulations — you''re officially under contract! 🏡 This is an exciting milestone. Our team is working hard to get you to the closing table smoothly. We''ll keep you updated every step of the way. Reply STOP to opt out.' WHERE id = 8;

UPDATE sms_templates SET body = 'Hi {{first_name}}, CONGRATULATIONS on your new home! 🎉🔑 It was an honor working with you at Alta Mortgage Group. Wishing you many happy years in your new home. If you ever need anything or want to refer a friend, we''re always here. Reply STOP to opt out.' WHERE id = 9;

